// Some portions generated by Claude
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;
import java.nio.file.Files;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Map;
import java.util.TreeMap;

import org.apache.commons.io.FileUtils;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryLanguage;
import org.eclipse.rdf4j.query.TupleQueryResult;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterAll;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.TestInstance;

/**
 * Milestone-3 engagement + parity tests for the Janino pipeline rung ({@link LmdbNativeJaninoPipeline}): generated
 * kernels must engage for supported probe-chain shapes (counters move, results identical to the generic evaluator) and
 * must stay silent when the master flag is off. WCOJ is disabled throughout so the leapfrog rung cannot absorb the
 * cyclic shapes first.
 */
@TestInstance(TestInstance.Lifecycle.PER_CLASS)
public class LmdbNativeJaninoPipelineTest {

	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final String WCOJ_FLAG = "rdf4j.lmdb.wcoj.enabled";
	private static final String CHAIN_QUERY = "PREFIX ex: <http://example.org/>\n"
			+ "SELECT * WHERE { ?a ex:knows ?b . ?b ex:knows ?c . FILTER(?a != ?c) }";
	private static final String CYCLE_QUERY = "PREFIX ex: <http://example.org/>\n"
			+ "SELECT * WHERE { ?a ex:knows ?b . ?b ex:knows ?c . ?c ex:knows ?d . ?d ex:knows ?a .\n"
			+ "  FILTER (?a != ?b && ?a != ?c && ?a != ?d && ?b != ?c && ?b != ?d && ?c != ?d) }";

	private final Map<String, String> savedProperties = new TreeMap<>();
	private File dataDir;
	private SailRepository repository;

	@BeforeAll
	public void setUp() throws Exception {
		save(NATIVE_FLAG, "true");
		save(WCOJ_FLAG, "false");
		save(LmdbNativeJaninoCodegen.ENABLED_PROPERTY, "true");
		save(LmdbNativeJaninoCodegen.THRESHOLD_ROWS_PROPERTY, "0");
		save("rdf4j.lmdb.csrCache.minProbes", "1");

		dataDir = Files.createTempDirectory("rdf4j-janino-pipeline").toFile();
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc,posc");
		config.setForceSync(false);
		repository = new SailRepository(new LmdbStore(dataDir, config));
		repository.init();

		ValueFactory vf = SimpleValueFactory.getInstance();
		IRI knows = vf.createIRI("http://example.org/knows");
		int[][] edges = {
				{ 0, 1 }, { 1, 2 }, { 2, 0 }, // triangle
				{ 3, 4 }, { 4, 5 }, { 5, 6 }, { 6, 3 }, // 4-cycle
				{ 0, 3 }, { 3, 0 }, { 1, 4 }, { 2, 5 }, { 5, 2 }, // cross links
				{ 7, 8 }, { 8, 9 }, { 9, 7 }, { 7, 0 }, { 8, 1 }, // second triangle + links
				{ 4, 4 }, // self loop
		};
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin();
			for (int[] edge : edges) {
				connection.add(vf.createIRI("http://example.org/p" + edge[0]), knows,
						vf.createIRI("http://example.org/p" + edge[1]));
			}
			connection.commit();
		}
	}

	@AfterAll
	public void tearDown() throws Exception {
		if (repository != null) {
			repository.shutDown();
		}
		if (dataDir != null) {
			FileUtils.deleteDirectory(dataDir);
		}
		for (Map.Entry<String, String> entry : savedProperties.entrySet()) {
			if (entry.getValue() == null) {
				System.clearProperty(entry.getKey());
			} else {
				System.setProperty(entry.getKey(), entry.getValue());
			}
		}
	}

	@BeforeEach
	public void resetCounters() {
		LmdbNativeJaninoPipeline.resetMetrics();
		LmdbNativeJaninoCodegen.resetForTests();
	}

	private void save(String key, String value) {
		savedProperties.putIfAbsent(key, System.getProperty(key));
		System.setProperty(key, value);
	}

	private List<String> rows(String query) {
		List<String> result = new ArrayList<>();
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult tupleResult = connection.prepareTupleQuery(QueryLanguage.SPARQL, query).evaluate()) {
			while (tupleResult.hasNext()) {
				BindingSet row = tupleResult.next();
				List<String> bindings = new ArrayList<>();
				for (String name : row.getBindingNames()) {
					bindings.add(name + "=" + row.getValue(name).stringValue());
				}
				Collections.sort(bindings);
				result.add(String.join("|", bindings));
			}
		}
		Collections.sort(result);
		return result;
	}

	private List<String> genericRows(String query) {
		System.setProperty(NATIVE_FLAG, "false");
		try {
			return rows(query);
		} finally {
			System.setProperty(NATIVE_FLAG, "true");
		}
	}

	private void warmUntilEngaged(String query) {
		for (int round = 0; round < 300 && LmdbNativeJaninoPipeline.OPENED.get() == 0L; round++) {
			rows(query);
		}
	}

	@Test
	public void chainQueryEngagesKernelAndMatchesGeneric() {
		List<String> expected = genericRows(CHAIN_QUERY);
		assertTrue(expected.size() > 5, "fixture too small to be meaningful");
		warmUntilEngaged(CHAIN_QUERY);
		assertTrue(LmdbNativeJaninoPipeline.PLANNED.get() > 0L, "pipeline shape was never recognized");
		assertTrue(LmdbNativeJaninoPipeline.OPENED.get() > 0L, "kernel never opened");
		assertEquals(expected, rows(CHAIN_QUERY));
		assertTrue(LmdbNativeJaninoPipeline.KERNEL_ROWS.get() > 0L, "kernel produced no rows");
	}

	@Test
	public void cycleQueryEngagesKernelAndMatchesGeneric() {
		List<String> expected = genericRows(CYCLE_QUERY);
		assertTrue(!expected.isEmpty(), "fixture has no 4-cycles");
		warmUntilEngaged(CYCLE_QUERY);
		assertTrue(LmdbNativeJaninoPipeline.OPENED.get() > 0L, "kernel never opened for the cycle shape");
		assertEquals(expected, rows(CYCLE_QUERY));
	}

	@Test
	public void countersStaySilentWhenDisabled() {
		System.setProperty(LmdbNativeJaninoCodegen.ENABLED_PROPERTY, "false");
		try {
			for (int round = 0; round < 10; round++) {
				rows(CHAIN_QUERY);
			}
			assertEquals(0L, LmdbNativeJaninoPipeline.PLANNED.get());
			assertEquals(0L, LmdbNativeJaninoPipeline.OPENED.get());
		} finally {
			System.setProperty(LmdbNativeJaninoCodegen.ENABLED_PROPERTY, "true");
		}
	}
}
